+TEST(SubmapsTest, TheRightNumberOfScansAreInserted) {
+  constexpr int kNumLaserFans = 10;
+  auto parameter_dictionary = common::MakeDictionary(
+      "return {"
+      "resolution = 0.05, "
+      "half_length = 10., "
+      "num_laser_fans = " +
+      std::to_string(kNumLaserFans) +
